import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"소송 문서 관리","description":"","frontmatter":{},"headers":[],"relativePath":"document/legal-docs.md","filePath":"document/legal-docs.md","lastUpdated":1784180250000}'),l={name:"document/legal-docs.md"};function i(n,a,s,h,d,u){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="소송-문서-관리" tabindex="-1">소송 문서 관리 <a class="header-anchor" href="#소송-문서-관리" aria-label="Permalink to &quot;소송 문서 관리&quot;">​</a></h1><p>프로젝트 진행 중 발생하는 각종 소송 사건과 관련된 문서(소장, 준비서면, 증거자료 등)를 사건별로 분류하여 체계적으로 기록하고 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 문서 관리 &gt; 소송 문서 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>소송 업무는 사건별로 방대한 분량의 문서가 발생하며, 시간 순서에 따른 증거 자료 관리가 매우 중요합니다. 본 페이지는 프로젝트와 관련된 법적 분쟁 내역을 &#39;사건(SuitCase)&#39; 단위로 묶어 관리함으로써, 복잡한 소송 기록을 한눈에 파악하고 관련 서류를 누락 없이 공유할 수 있도록 지원합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>사건별 문서 그룹화</strong>: 개별 소송 사건을 등록하고, 해당 사건에 속하는 문서들을 별도로 필터링하여 조회 가능</li><li><strong>소송 단계별 카테고리</strong>: 소 제기, 준비 서면, 판결문 등 소송 단계나 문서 성격에 따른 카테고리 분류</li><li><strong>신규 사건 즉시 등록</strong>: 문서 작성 중에도 새로운 소송 사건(사건번호, 사건명 등)을 즉시 생성하여 연동 가능</li><li><strong>다중 자원 관리</strong>: 소송 관련 대용량 파일 첨부 및 외부 법률 시스템 링크 참조 지원</li><li><strong>중요 문서 스크랩</strong>: 담당자별로 빈번히 참조해야 하는 소송 문서를 개인 보관함에 추가</li><li><strong>조회 이력 관리</strong>: 문서, 파일, 링크별 조회수 확인을 통해 관련 자료의 검토 현황 파악</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-목록-및-사건-필터링" tabindex="-1">1. 목록 및 사건 필터링 <a class="header-anchor" href="#_1-목록-및-사건-필터링" aria-label="Permalink to &quot;1. 목록 및 사건 필터링&quot;">​</a></h3><p>특정 소송 사건이나 분류에 해당하는 문서를 찾는 영역입니다.</p><ul><li><strong>사건 선택 필터</strong>: 등록된 소송 사건 목록에서 특정 사건을 선택하면 해당 사건과 관련된 모든 기록이 표시됩니다.</li><li><strong>카테고리 탭</strong>: 일반/법률 문서의 공통 분류 체계를 탭 형태로 제공하여 빠른 필터링을 지원합니다.</li></ul><h3 id="_2-소송-문서-목록" tabindex="-1">2. 소송 문서 목록 <a class="header-anchor" href="#_2-소송-문서-목록" aria-label="Permalink to &quot;2. 소송 문서 목록&quot;">​</a></h3><p>사건명, 카테고리, 제목, 작성자, 조회수 등을 일람표 형태로 표시합니다.</p><ul><li><strong>사건 식별</strong>: 각 문서 행에는 연동된 소송 사건 정보가 함께 표시되어 어떤 분쟁에 관한 서류인지 즉시 식별 가능합니다.</li></ul><h3 id="_3-상세-보기-및-자원-확인" tabindex="-1">3. 상세 보기 및 자원 확인 <a class="header-anchor" href="#_3-상세-보기-및-자원-확인" aria-label="Permalink to &quot;3. 상세 보기 및 자원 확인&quot;">​</a></h3><p>소송 문서의 전문과 첨부된 증거 자료 등을 확인하는 화면입니다.</p><ul><li><strong>증거 자료 관리</strong>: 첨부된 이미지나 PDF 등의 파일을 즉시 다운로드하여 검토할 수 있습니다.</li><li><strong>연관 링크</strong>: 판례 정보나 법원 전자소송 시스템 링크 등을 참조 정보로 활용합니다.</li></ul><h3 id="_4-문서-작성-및-수정" tabindex="-1">4. 문서 작성 및 수정 <a class="header-anchor" href="#_4-문서-작성-및-수정" aria-label="Permalink to &quot;4. 문서 작성 및 수정&quot;">​</a></h3><p>새로운 소송 기록을 등록하거나 보완하는 화면입니다.</p><ul><li><strong>사건 매칭</strong>: 문서를 작성할 때 반드시 관련된 &#39;소송 사건&#39;을 선택해야 합니다. 만약 목록에 없는 새로운 사건이라면 [사건 추가] 기능을 통해 즉시 등록할 수 있습니다.</li><li><strong>파일 설명</strong>: 소송 증거 자료 업로드 시 각 파일이 어떤 증거 번호(예: 갑 제1호증)나 의미를 갖는지 설명을 덧붙여 관리합니다.</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="사건-suitcase-중심의-관리" tabindex="-1">사건(SuitCase) 중심의 관리 <a class="header-anchor" href="#사건-suitcase-중심의-관리" aria-label="Permalink to &quot;사건(SuitCase) 중심의 관리&quot;">​</a></h3><p>소송 문서는 일반 문서와 달리 <strong>사건번호와 사건명</strong>을 중심으로 관리됩니다. 문서를 업로드하기 전, 반드시 해당 문서가 귀속될 소송 사건이 정확히 선택되었는지 확인해야 합니다. 사건별 필터 기능을 활용하면 특정 분쟁의 시작부터 결말까지의 흐름을 파악하기 용이합니다.</p><h3 id="증거-자료의-체계적-설명" tabindex="-1">증거 자료의 체계적 설명 <a class="header-anchor" href="#증거-자료의-체계적-설명" aria-label="Permalink to &quot;증거 자료의 체계적 설명&quot;">​</a></h3><p>첨부 파일 업로드 시 단순히 파일만 올리는 것이 아니라, &#39;파일 설명&#39; 필드에 <strong>증거 순번이나 문서의 요지</strong>를 간략히 기재하십시오. 이는 추후 수많은 파일 중에서 필요한 증명 자료를 빠르게 검색하고 식별하는 데 큰 도움이 됩니다.</p><h3 id="실시간-협업과-스크랩" tabindex="-1">실시간 협업과 스크랩 <a class="header-anchor" href="#실시간-협업과-스크랩" aria-label="Permalink to &quot;실시간 협업과 스크랩&quot;">​</a></h3><p>법무팀이나 외부 법률 대리인과 공유해야 하는 핵심 문서는 스크랩 기능을 활용하십시오. 본인의 스크랩 목록에 추가해 두면, 복잡한 트리 구조를 뒤지지 않고도 개인 메뉴에서 즉시 접근할 수 있어 급박한 소송 일정 대응에 효율적입니다.</p>',27)])])}const p=t(l,[["render",i]]);export{g as __pageData,p as default};
